previewCss:
.darma-loader-cssloaders-github-05 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 5px;
      min-width: 52px;
      min-height: 16px;
    }
    .darma-loader-cssloaders-github-05 i {
      display: block;
      width: 8px;
      height: 8px;
      border-radius: 50%;
      background: var(--loader-color);
      animation: darma-loader-cssloaders-github-05-dotPulse 0.95s ease-in-out infinite;
    }
    .darma-loader-cssloaders-github-05 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-cssloaders-github-05 i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-cssloaders-github-05 i:nth-child(3) { animation-delay: 0.24s; }
.darma-loader-cssloaders-github-05 i:nth-child(4) { animation-delay: 0.36s; }
    @keyframes darma-loader-cssloaders-github-05-dotPulse { 0%, 100% { transform: translateY(0); opacity: .45; } 45% { transform: translateY(-12px); opacity: 1; } }

